#include<bits/stdc++.h>
using namespace std;
int a[100010],b[100010];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        b[x]=i;
    }
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        a[i]=b[x];
    }
    vector<int> v;
    for(int i=1;i<=n;i++)
    {
        int pos=lower_bound(v.begin(),v.end(),a[i])-v.begin();
        if(pos==v.size())
        {
            v.push_back(a[i]);
        }
        else
        {
            v[pos]=a[i];
        }
    }
    printf("%d",v.size());
    return 0;
}
